import cProfile, functools, pstats, io

def profiled(sort='cumulative', n=20):
    def deco(func):
        @functools.wraps(func)
        def wrapper(*args, **kw):
            with cProfile.Profile() as pr:
                result = func(*args, **kw)
            buf = io.StringIO()
            pstats.Stats(pr, stream=buf).strip_dirs().sort_stats(sort).print_stats(n)
            print(buf.getvalue())
            return result
        return wrapper
    return deco

